protected int complement(int extra) {

    extra = RADIX-extra;
    for (int i = 0; i < mant.length; i++) {
        mant[i] = RADIX-mant[i]-1;
    }

    int rh = extra / RADIX;
    extra = extra - rh * RADIX;
    for (int i = 0; i < mant.length; i++) {
        final int r = mant[i] + rh;
        rh = r / RADIX;
        mant[i] = r - rh * RADIX;
    }

    return extra;
}


