protected String dfp2string() {
    char buffer[] = new char[mant.length*4 + 20];
    int p = 1;
    int q;
    int e = exp;
    boolean pointInserted = false;

    buffer[0] = ' ';

    if (e <= 0) {
        buffer[p++] = '0';
        buffer[p++] = '.';
        pointInserted = true;
    }

    while (e < 0) {
        buffer[p++] = '0';
        buffer[p++] = '0';
        buffer[p++] = '0';
        buffer[p++] = '0';
        e++;
    }

    for (int i = mant.length - 1; i >= 0; i--) {
        buffer[p++] = (char) ((mant[i] / 1000) + '0');
        buffer[p++] = (char) (((mant[i] / 100) % 10) + '0');
        buffer[p++] = (char) (((mant[i] / 10) % 10) + '0');
        buffer[p++] = (char) (((mant[i]) % 10) + '0');
        if (--e == 0) {
            buffer[p++] = '.';
            pointInserted = true;
        }
    }

    while (e > 0) {
        buffer[p++] = '0';
        buffer[p++] = '0';
        buffer[p++] = '0';
        buffer[p++] = '0';
        e--;
    }

    if (!pointInserted) {

        buffer[p++] = '.';
    }


    q = 1;
    while (buffer[q] == '0') {
        q++;
    }
    if (buffer[q] == '.') {
        q--;
    }


    while (buffer[p-1] == '0') {
        p--;
    }


    if (sign < 0) {
        buffer[--q] = '-';
    }

