        for (int i = 0; i < mant.length; i++) {
            dividend[i + 1] = remainder[i];
        }
    }


    md = mant.length;  
    for (int i = mant.length + 1; i >= 0; i--) {
        if (quotient[i] != 0) {
            md = i;
            break;
        }
    }


    for (int i=0; i<mant.length; i++) {
        result.mant[mant.length-i-1] = quotient[md-i];
    }


    result.exp = exp - divisor.exp + md - mant.length;
