            ra[row][row] = rDiag[row];
            for (int col = row + 1; col < n; col++) {
                ra[row][col] = qrt[col][row];
            }
        }
        cachedR = MatrixUtils.createRealMatrix(ra);
    }


    return cachedR;
}


