    SparseFieldVector<T> res = (SparseFieldVector<T>)copy();
    OpenIntToFieldHashMap<T>.Iterator iter = v.getEntries().iterator();
    while (iter.hasNext()) {
        iter.advance();
        int key = iter.key();
