public void search(UnivariateFunction func, GoalType goal, double xA, double xB) {
    evaluations.resetCount();
    final boolean isMinim = goal == GoalType.MINIMIZE;

    double fA = eval(func, xA);
    double fB = eval(func, xB);
    if (isMinim ?
        fA < fB :
        fA > fB) {

        double tmp = xA;
        xA = xB;
        xB = tmp;

        tmp = fA;
        fA = fB;
        fB = tmp;
    }

    double xC = xB + GOLD * (xB - xA);
    double fC = eval(func, xC);

    while (isMinim ? fC < fB : fC > fB) {
        double tmp1 = (xB - xA) * (fB - fC);
        double tmp2 = (xB - xC) * (fB - fA);

        double val = tmp2 - tmp1;
        double denom = Math.abs(val) < EPS_MIN ? 2 * EPS_MIN : 2 * val;

        double w = xB - ((xB - xC) * tmp2 - (xB - xA) * tmp1) / denom;
        double wLim = xB + growLimit * (xC - xB);

        double fW;
        if ((w - xC) * (xB - w) > 0) {
            fW = eval(func, w);
            if (isMinim ?
                fW < fC :
                fW > fC) {
                xA = xB;
                xB = w;
                fA = fB;
                fB = fW;
                break;
            } else if (isMinim ?
                       fW > fB :
                       fW < fB) {
                xC = w;
                fC = fW;
                break;
            }
            w = xC + GOLD * (xC - xB);
            fW = eval(func, w);
        } else if ((w - wLim) * (wLim - xC) >= 0) {
            w = wLim;
            fW = eval(func, w);
        } else if ((w - wLim) * (xC - w) > 0) {
            fW = eval(func, w);
            if (isMinim ?
                fW < fC :
                fW > fC) {
                xB = xC;
                xC = w;
                w = xC + GOLD * (xC - xB);
                fB = fC;
                fC =fW;
                fW = eval(func, w);
            }
        } else {
            w = xC + GOLD * (xC - xB);
            fW = eval(func, w);
        }

        xA = xB;
        fA = fB;
        xB = xC;
        fB = fC;
        xC = w;
        fC = fW;
    }

    lo = xA;
    fLo = fA;
    mid = xB;
    fMid = fB;
    hi = xC;
    fHi = fC;

    if (lo > hi) {
        double tmp = lo;
        lo = hi;
        hi = tmp;

        tmp = fLo;
        fLo = fHi;
        fHi = tmp;
    }
}

public boolean converged(final int iteration,
                         final UnivariatePointValuePair previous,
                         final UnivariatePointValuePair current) {
    if (maxIterationCount != ITERATION_CHECK_DISABLED) {
        if (iteration >= maxIterationCount) {
            return true;
        }
    }

    final double p = previous.getValue();
    final double c = current.getValue();
    final double difference = FastMath.abs(p - c);
    final double size = FastMath.max(FastMath.abs(p), FastMath.abs(c));
    return difference <= size * getRelativeThreshold() ||
        difference <= getAbsoluteThreshold();
}

public int compare(final UnivariatePointValuePair o1,
                   final UnivariatePointValuePair o2) {
    if (o1 == null) {
        return (o2 == null) ? 0 : 1;
    } else if (o2 == null) {
        return -1;
    }
    final double v1 = o1.getValue();
    final double v2 = o2.getValue();
    return (goal == GoalType.MINIMIZE) ?
        Double.compare(v1, v2) : Double.compare(v2, v1);
}


