        while (true) {
            final long r = rng.nextLong();
            if (r >= lower && r <= upper) {
                return r;
            }
        }
    } else if (max < Integer.MAX_VALUE){

        return lower + getSecRan().nextInt((int) max);
    } else {

        return lower + nextLong(getSecRan(), max);
    }
}


