public double[] nextVector() {
    final double[] v = new double[dimension];




    double normSq = 0;
    for (int i = 0; i < dimension; i++) {
        final double comp = rand.nextGaussian();
        v[i] = comp;
        normSq += comp * comp;
    }

    final double f = 1 / FastMath.sqrt(normSq);
    for (int i = 0; i < dimension; i++) {
        v[i] *= f;
    }

    return v;
}


