    return (((v1 / n1) + (v2 / n2)) * ((v1 / n1) + (v2 / n2))) /
    ((v1 * v1) / (n1 * n1 * (n1 - 1d)) + (v2 * v2) /
            (n2 * n2 * (n2 - 1d)));
}


