public void addData(final double x,final double y) {
    if (n == 0) {
        xbar = x;
        ybar = y;
    } else {
        if( hasIntercept ){
            final double fact1 = 1.0 + n;
            final double fact2 = n / (1.0 + n);
            final double dx = x - xbar;
            final double dy = y - ybar;
            sumXX += dx * dx * fact2;
            sumYY += dy * dy * fact2;
            sumXY += dx * dy * fact2;
            xbar += dx / fact1;
            ybar += dy / fact1;
        }
     }
    if( !hasIntercept ){
        sumXX += x * x ;
        sumYY += y * y ;
        sumXY += x * y ;
    }
    sumX += x;
    sumY += y;
    n++;
}


