                LocalizedFormats.NOT_POWER_OF_TWO,
                Integer.valueOf(n));
    }


    double[] yPrevious = new double[n];
    double[] yCurrent  = x.clone();


    for (int j = 1; j < n; j <<= 1) {


        final double[] yTmp = yCurrent;
        yCurrent  = yPrevious;
        yPrevious = yTmp;


        for (int i = 0; i < halfN; ++i) {

