private void transformToLowerBiDiagonal() {

    final int m = householderVectors.length;
    final int n = householderVectors[0].length;
    for (int k = 0; k < m; k++) {


        final double[] hK = householderVectors[k];
        double xNormSqr = 0;
        for (int j = k; j < n; ++j) {
            final double c = hK[j];
            xNormSqr += c * c;
        }
        final double a = (hK[k] > 0) ? -FastMath.sqrt(xNormSqr) : FastMath.sqrt(xNormSqr);
        main[k] = a;
        if (a != 0.0) {
            hK[k] -= a;
            for (int i = k + 1; i < m; ++i) {
                final double[] hI = householderVectors[i];
                double alpha = 0;
                for (int j = k; j < n; ++j) {
                    alpha -= hI[j] * hK[j];
                }
                alpha /= a * householderVectors[k][k];
                for (int j = k; j < n; ++j) {
                    hI[j] -= alpha * hK[j];
                }
            }
        }

        if (k < m - 1) {

            final double[] hKp1 = householderVectors[k + 1];
            xNormSqr = 0;
            for (int i = k + 1; i < m; ++i) {
                final double c = householderVectors[i][k];
                xNormSqr += c * c;
            }
            final double b = (hKp1[k] > 0) ? -FastMath.sqrt(xNormSqr) : FastMath.sqrt(xNormSqr);
            secondary[k] = b;
            if (b != 0.0) {
                hKp1[k] -= b;
                for (int j = k + 1; j < n; ++j) {
                    double beta = 0;
                    for (int i = k + 1; i < m; ++i) {
                        final double[] hI = householderVectors[i];
                        beta -= hI[j] * hI[k];
                    }
                    beta /= b * hKp1[k];
                    for (int i = k + 1; i < m; ++i) {
                        final double[] hI = householderVectors[i];
                        hI[j] -= beta * hI[k];
                    }
                }
            }
        }

    }
}


private void transformToUpperBiDiagonal() {

    final int m = householderVectors.length;
    final int n = householderVectors[0].length;
    for (int k = 0; k < n; k++) {


        double xNormSqr = 0;
        for (int i = k; i < m; ++i) {
            final double c = householderVectors[i][k];
            xNormSqr += c * c;
        }
        final double[] hK = householderVectors[k];
        final double a = (hK[k] > 0) ? -FastMath.sqrt(xNormSqr) : FastMath.sqrt(xNormSqr);
        main[k] = a;
        if (a != 0.0) {
            hK[k] -= a;
            for (int j = k + 1; j < n; ++j) {
                double alpha = 0;
                for (int i = k; i < m; ++i) {
                    final double[] hI = householderVectors[i];
                    alpha -= hI[j] * hI[k];
                }
                alpha /= a * householderVectors[k][k];
                for (int i = k; i < m; ++i) {
                    final double[] hI = householderVectors[i];
                    hI[j] -= alpha * hI[k];
                }
            }
        }

        if (k < n - 1) {

            xNormSqr = 0;
            for (int j = k + 1; j < n; ++j) {
                final double c = hK[j];
                xNormSqr += c * c;
            }
            final double b = (hK[k + 1] > 0) ? -FastMath.sqrt(xNormSqr) : FastMath.sqrt(xNormSqr);
            secondary[k] = b;
            if (b != 0.0) {
                hK[k + 1] -= b;
                for (int i = k + 1; i < m; ++i) {
                    final double[] hI = householderVectors[i];
                    double beta = 0;
                    for (int j = k + 1; j < n; ++j) {
                        beta -= hI[j] * hK[j];
                    }
                    beta /= b * hK[k + 1];
                    for (int j = k + 1; j < n; ++j) {
                        hI[j] -= beta * hK[j];
                    }
                }
            }
        }

    }
}


