private void ensureZero(final double value) throws NumberIsTooLargeException {
    if (!Precision.equals(0.0, value, 1)) {
        throw new NumberIsTooLargeException(FastMath.abs(value), 0, true);
    }
}


private Complex cdiv(final double xr, final double xi,
                     final double yr, final double yi) {
    return new Complex(xr, xi).divide(new Complex(yr, yi));
}


private void findEigenVectors(final double[][] householderMatrix) {
    final double[][]z = householderMatrix.clone();
    final int n = main.length;
    realEigenvalues = new double[n];
    imagEigenvalues = new double[n];
    final double[] e = new double[n];
    for (int i = 0; i < n - 1; i++) {
        realEigenvalues[i] = main[i];
        e[i] = secondary[i];
    }
    realEigenvalues[n - 1] = main[n - 1];
    e[n - 1] = 0;


    double maxAbsoluteValue = 0;
    for (int i = 0; i < n; i++) {
        if (FastMath.abs(realEigenvalues[i]) > maxAbsoluteValue) {
            maxAbsoluteValue = FastMath.abs(realEigenvalues[i]);
        }
        if (FastMath.abs(e[i]) > maxAbsoluteValue) {
            maxAbsoluteValue = FastMath.abs(e[i]);
        }
    }

    if (maxAbsoluteValue != 0) {
        for (int i=0; i < n; i++) {
            if (FastMath.abs(realEigenvalues[i]) <= Precision.EPSILON * maxAbsoluteValue) {
                realEigenvalues[i] = 0;
            }
            if (FastMath.abs(e[i]) <= Precision.EPSILON * maxAbsoluteValue) {
                e[i]=0;
            }
        }
    }

    for (int j = 0; j < n; j++) {
        int its = 0;
        int m;
        do {
            for (m = j; m < n - 1; m++) {
                double delta = FastMath.abs(realEigenvalues[m]) +
                    FastMath.abs(realEigenvalues[m + 1]);
                if (FastMath.abs(e[m]) + delta == delta) {
                    break;
                }
            }
            if (m != j) {
                if (its == maxIter) {
                    throw new MaxCountExceededException(LocalizedFormats.CONVERGENCE_FAILED,
                                                        maxIter);
                }
                its++;
                double q = (realEigenvalues[j + 1] - realEigenvalues[j]) / (2 * e[j]);
                double t = FastMath.sqrt(1 + q * q);
                if (q < 0.0) {
                    q = realEigenvalues[m] - realEigenvalues[j] + e[j] / (q - t);
                } else {
                    q = realEigenvalues[m] - realEigenvalues[j] + e[j] / (q + t);
                }
                double u = 0.0;
                double s = 1.0;
                double c = 1.0;
                int i;
                for (i = m - 1; i >= j; i--) {
                    double p = s * e[i];
                    double h = c * e[i];
                    if (FastMath.abs(p) >= FastMath.abs(q)) {
                        c = q / p;
                        t = FastMath.sqrt(c * c + 1.0);
                        e[i + 1] = p * t;
                        s = 1.0 / t;
                        c = c * s;
                    } else {
                        s = p / q;
                        t = FastMath.sqrt(s * s + 1.0);
                        e[i + 1] = q * t;
                        c = 1.0 / t;
                        s = s * c;
                    }
                    if (e[i + 1] == 0.0) {
                        realEigenvalues[i + 1] -= u;
                        e[m] = 0.0;
                        break;
                    }
                    q = realEigenvalues[i + 1] - u;
                    t = (realEigenvalues[i] - q) * s + 2.0 * c * h;
                    u = s * t;
                    realEigenvalues[i + 1] = q + u;
                    q = c * t - h;
                    for (int ia = 0; ia < n; ia++) {
                        p = z[ia][i + 1];
                        z[ia][i + 1] = s * z[ia][i] + c * p;
                        z[ia][i] = c * z[ia][i] - s * p;
                    }
                }
                if (t == 0.0 && i >= j) {
                    continue;
                }
                realEigenvalues[j] -= u;
                e[j] = q;
                e[m] = 0.0;
            }
        } while (m != j);
    }


    for (int i = 0; i < n; i++) {
        int k = i;
        double p = realEigenvalues[i];
        for (int j = i + 1; j < n; j++) {
            if (realEigenvalues[j] > p) {
                k = j;
                p = realEigenvalues[j];
            }
        }
        if (k != i) {
            realEigenvalues[k] = realEigenvalues[i];
            realEigenvalues[i] = p;
            for (int j = 0; j < n; j++) {
                p = z[j][i];
                z[j][i] = z[j][k];
                z[j][k] = p;
            }
        }
    }


    maxAbsoluteValue = 0;
    for (int i = 0; i < n; i++) {
        if (FastMath.abs(realEigenvalues[i]) > maxAbsoluteValue) {
            maxAbsoluteValue=FastMath.abs(realEigenvalues[i]);
        }
    }

    if (maxAbsoluteValue != 0.0) {
        for (int i=0; i < n; i++) {
            if (FastMath.abs(realEigenvalues[i]) < Precision.EPSILON * maxAbsoluteValue) {
                realEigenvalues[i] = 0;
            }
        }
    }
    eigenvectors = new ArrayRealVector[n];
    final double[] tmp = new double[n];
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < n; j++) {
            tmp[j] = z[j][i];
        }
        eigenvectors[i] = new ArrayRealVector(tmp);
    }
}


private void findEigenVectorsFromSchur(final SchurTransformer schur)
    throws MathArithmeticException {
    final double[][] matrixT = schur.getT().getData();
    final double[][] matrixP = schur.getP().getData();

    final int n = matrixT.length;


    double norm = 0.0;
    for (int i = 0; i < n; i++) {
       for (int j = FastMath.max(i - 1, 0); j < n; j++) {
          norm = norm + FastMath.abs(matrixT[i][j]);
       }
    }


    if (Precision.equals(norm, 0.0, EPSILON)) {
       throw new MathArithmeticException(LocalizedFormats.ZERO_NORM);
    }



    double r = 0.0;
    double s = 0.0;
    double z = 0.0;

    for (int idx = n - 1; idx >= 0; idx--) {
        double p = realEigenvalues[idx];
        double q = imagEigenvalues[idx];

        if (Precision.equals(q, 0.0)) {

            int l = idx;
            matrixT[idx][idx] = 1.0;
            for (int i = idx - 1; i >= 0; i--) {
                double w = matrixT[i][i] - p;
                r = 0.0;
                for (int j = l; j <= idx; j++) {
                    r = r + matrixT[i][j] * matrixT[j][idx];
                }
                if (Precision.compareTo(imagEigenvalues[i], 0.0, EPSILON) < 0.0) {
                    z = w;
                    s = r;
                } else {
                    l = i;
                    if (Precision.equals(imagEigenvalues[i], 0.0)) {
                        if (w != 0.0) {
                            matrixT[i][idx] = -r / w;
                        } else {
                            matrixT[i][idx] = -r / (Precision.EPSILON * norm);
                        }
                    } else {

                        double x = matrixT[i][i + 1];
                        double y = matrixT[i + 1][i];
                        q = (realEigenvalues[i] - p) * (realEigenvalues[i] - p) +
                            imagEigenvalues[i] * imagEigenvalues[i];
                        double t = (x * s - z * r) / q;
                        matrixT[i][idx] = t;
                        if (FastMath.abs(x) > FastMath.abs(z)) {
                            matrixT[i + 1][idx] = (-r - w * t) / x;
                        } else {
                            matrixT[i + 1][idx] = (-s - y * t) / z;
                        }
                    }


                    double t = FastMath.abs(matrixT[i][idx]);
                    if ((Precision.EPSILON * t) * t > 1) {
                        for (int j = i; j <= idx; j++) {
                            matrixT[j][idx] = matrixT[j][idx] / t;
                        }
                    }
                }
            }
        } else if (q < 0.0) {

            int l = idx - 1;


            if (FastMath.abs(matrixT[idx][idx - 1]) > FastMath.abs(matrixT[idx - 1][idx])) {
                matrixT[idx - 1][idx - 1] = q / matrixT[idx][idx - 1];
                matrixT[idx - 1][idx]     = -(matrixT[idx][idx] - p) / matrixT[idx][idx - 1];
            } else {
                final Complex result = cdiv(0.0, -matrixT[idx - 1][idx],
                                            matrixT[idx - 1][idx - 1] - p, q);
                matrixT[idx - 1][idx - 1] = result.getReal();
                matrixT[idx - 1][idx]     = result.getImaginary();
            }

            matrixT[idx][idx - 1] = 0.0;
            matrixT[idx][idx]     = 1.0;

            for (int i = idx - 2; i >= 0; i--) {
                double ra = 0.0;
                double sa = 0.0;
                for (int j = l; j <= idx; j++) {
                    ra = ra + matrixT[i][j] * matrixT[j][idx - 1];
                    sa = sa + matrixT[i][j] * matrixT[j][idx];
                }
                double w = matrixT[i][i] - p;

                if (Precision.compareTo(imagEigenvalues[i], 0.0, EPSILON) < 0.0) {
                    z = w;
                    r = ra;
                    s = sa;
                } else {
                    l = i;
                    if (Precision.equals(imagEigenvalues[i], 0.0)) {
                        final Complex c = cdiv(-ra, -sa, w, q);
                        matrixT[i][idx - 1] = c.getReal();
                        matrixT[i][idx] = c.getImaginary();
                    } else {

                        double x = matrixT[i][i + 1];
                        double y = matrixT[i + 1][i];
                        double vr = (realEigenvalues[i] - p) * (realEigenvalues[i] - p) +
                                    imagEigenvalues[i] * imagEigenvalues[i] - q * q;
                        final double vi = (realEigenvalues[i] - p) * 2.0 * q;
                        if (Precision.equals(vr, 0.0) && Precision.equals(vi, 0.0)) {
                            vr = Precision.EPSILON * norm *
                                 (FastMath.abs(w) + FastMath.abs(q) + FastMath.abs(x) +
                                  FastMath.abs(y) + FastMath.abs(z));
                        }
                        final Complex c     = cdiv(x * r - z * ra + q * sa,
                                                   x * s - z * sa - q * ra, vr, vi);
                        matrixT[i][idx - 1] = c.getReal();
                        matrixT[i][idx]     = c.getImaginary();

                        if (FastMath.abs(x) > (FastMath.abs(z) + FastMath.abs(q))) {
                            matrixT[i + 1][idx - 1] = (-ra - w * matrixT[i][idx - 1] +
                                                       q * matrixT[i][idx]) / x;
                            matrixT[i + 1][idx]     = (-sa - w * matrixT[i][idx] -
                                                       q * matrixT[i][idx - 1]) / x;
                        } else {
                            final Complex c2        = cdiv(-r - y * matrixT[i][idx - 1],
                                                           -s - y * matrixT[i][idx], z, q);
                            matrixT[i + 1][idx - 1] = c2.getReal();
                            matrixT[i + 1][idx]     = c2.getImaginary();
                        }
                    }


                    double t = FastMath.max(FastMath.abs(matrixT[i][idx - 1]),
                                            FastMath.abs(matrixT[i][idx]));
                    if ((Precision.EPSILON * t) * t > 1) {
                        for (int j = i; j <= idx; j++) {
                            matrixT[j][idx - 1] = matrixT[j][idx - 1] / t;
                            matrixT[j][idx]     = matrixT[j][idx] / t;
                        }
                    }
                }
            }
        }
    }


    for (int i = 0; i < n; i++) {
        if (i < 0 | i > n - 1) {
            for (int j = i; j < n; j++) {
                matrixP[i][j] = matrixT[i][j];
            }
        }
    }


    for (int j = n - 1; j >= 0; j--) {
        for (int i = 0; i <= n - 1; i++) {
            z = 0.0;
            for (int k = 0; k <= FastMath.min(j, n - 1); k++) {
                z = z + matrixP[i][k] * matrixT[k][j];
            }
            matrixP[i][j] = z;
        }
    }

    eigenvectors = new ArrayRealVector[n];
    final double[] tmp = new double[n];
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < n; j++) {
            tmp[j] = matrixP[j][i];
        }
        eigenvectors[i] = new ArrayRealVector(tmp);
    }
}


private SchurTransformer transformToSchur(final RealMatrix matrix) {
    final SchurTransformer schurTransform = new SchurTransformer(matrix);
    final double[][] matT = schurTransform.getT().getData();

    realEigenvalues = new double[matT.length];
    imagEigenvalues = new double[matT.length];

    for (int i = 0; i < realEigenvalues.length; i++) {
        if (i == (realEigenvalues.length - 1) ||
            Precision.equals(matT[i + 1][i], 0.0, EPSILON)) {
            realEigenvalues[i] = matT[i][i];
        } else {
            final double x = matT[i + 1][i + 1];
            final double p = 0.5 * (matT[i][i] - x);
            final double z = FastMath.sqrt(FastMath.abs(p * p + matT[i + 1][i] * matT[i][i + 1]));
            realEigenvalues[i] = x + p;
            imagEigenvalues[i] = z;
            realEigenvalues[i + 1] = x + p;
            imagEigenvalues[i + 1] = -z;
            i++;
        }
    }
    return schurTransform;
}


private void transformToTridiagonal(final RealMatrix matrix) {

    transformer = new TriDiagonalTransformer(matrix);
    main = transformer.getMainDiagonalRef();
    secondary = transformer.getSecondaryDiagonalRef();
}


private void transform() {
    final int n = householderVectors.length;
    final int high = n - 1;

    for (int m = 1; m <= high - 1; m++) {

        double scale = 0;
        for (int i = m; i <= high; i++) {
            scale += FastMath.abs(householderVectors[i][m - 1]);
        }

        if (!Precision.equals(scale, 0)) {

            double h = 0;
            for (int i = high; i >= m; i--) {
                ort[i] = householderVectors[i][m - 1] / scale;
                h += ort[i] * ort[i];
            }
            final double g = (ort[m] > 0) ? -FastMath.sqrt(h) : FastMath.sqrt(h);

            h = h - ort[m] * g;
            ort[m] = ort[m] - g;




            for (int j = m; j < n; j++) {
                double f = 0;
                for (int i = high; i >= m; i--) {
                    f += ort[i] * householderVectors[i][j];
                }
                f = f / h;
                for (int i = m; i <= high; i++) {
                    householderVectors[i][j] -= f * ort[i];
                }
            }

            for (int i = 0; i <= high; i++) {
                double f = 0;
                for (int j = high; j >= m; j--) {
                    f += ort[j] * householderVectors[i][j];
                }
                f = f / h;
                for (int j = m; j <= high; j++) {
                    householderVectors[i][j] -= f * ort[j];
                }
            }

            ort[m] = scale * ort[m];
            householderVectors[m][m - 1] = scale * g;
        }
    }
}


private int computeKey(int row, int column) {
    return row * columns + column;
}


private OpenIntToDoubleHashMap getEntries() {
    return entries;
}


private double getLInfDistance(OpenMapRealVector v)
    throws DimensionMismatchException {
    checkVectorDimensions(v.getDimension());
    double max = 0;
    Iterator iter = entries.iterator();
    while (iter.hasNext()) {
        iter.advance();
        double delta = FastMath.abs(iter.value() - v.getEntry(iter.key()));
        if (delta > max) {
            max = delta;
        }
    }
    iter = v.getEntries().iterator();
    while (iter.hasNext()) {
        iter.advance();
        int key = iter.key();
        if (!entries.containsKey(key)) {
            if (iter.value() > max) {
                max = iter.value();
            }
        }
    }
    return max;
}


private void computeShift(final int l, final int idx, final int iteration, final ShiftInfo shift) {

    shift.x = matrixT[idx][idx];
    shift.y = shift.w = 0.0;
    if (l < idx) {
        shift.y = matrixT[idx - 1][idx - 1];
        shift.w = matrixT[idx][idx - 1] * matrixT[idx - 1][idx];
    }


    if (iteration == 10) {
        shift.exShift += shift.x;
        for (int i = 0; i <= idx; i++) {
            matrixT[i][i] -= shift.x;
        }
        final double s = FastMath.abs(matrixT[idx][idx - 1]) + FastMath.abs(matrixT[idx - 1][idx - 2]);
        shift.x = 0.75 * s;
        shift.y = 0.75 * s;
        shift.w = -0.4375 * s * s;
    }


    if (iteration == 30) {
        double s = (shift.y - shift.x) / 2.0;
        s = s * s + shift.w;
        if (s > 0.0) {
            s = FastMath.sqrt(s);
            if (shift.y < shift.x) {
                s = -s;
            }
            s = shift.x - shift.w / ((shift.y - shift.x) / 2.0 + s);
            for (int i = 0; i <= idx; i++) {
                matrixT[i][i] -= s;
            }
            shift.exShift += s;
            shift.x = shift.y = shift.w = 0.964;
        }
    }
}


private int findSmallSubDiagonalElement(final int startIdx, final double norm) {
    int l = startIdx;
    while (l > 0) {
        double s = FastMath.abs(matrixT[l - 1][l - 1]) + FastMath.abs(matrixT[l][l]);
        if (s == 0.0) {
            s = norm;
        }
        if (FastMath.abs(matrixT[l][l - 1]) < epsilon * s) {
            break;
        }
        l--;
    }
    return l;
}


private double getNorm() {
    double norm = 0.0;
    for (int i = 0; i < matrixT.length; i++) {

        for (int j = FastMath.max(i - 1, 0); j < matrixT.length; j++) {
            norm += FastMath.abs(matrixT[i][j]);
        }
    }
    return norm;
}


private int initQRStep(int il, final int iu, final ShiftInfo shift, double[] hVec) {

    int im = iu - 2;
    while (im >= il) {
        final double z = matrixT[im][im];
        final double r = shift.x - z;
        double s = shift.y - z;
        hVec[0] = (r * s - shift.w) / matrixT[im + 1][im] + matrixT[im][im + 1];
        hVec[1] = matrixT[im + 1][im + 1] - z - r - s;
        hVec[2] = matrixT[im + 2][im + 1];

        if (im == il) {
            break;
        }

        final double lhs = FastMath.abs(matrixT[im][im - 1]) * (FastMath.abs(hVec[1]) + FastMath.abs(hVec[2]));
        final double rhs = FastMath.abs(hVec[0]) * (FastMath.abs(matrixT[im - 1][im - 1]) +
                                                    FastMath.abs(z) +
                                                    FastMath.abs(matrixT[im + 1][im + 1]));

        if (lhs < epsilon * rhs) {
            break;
        }
        im--;
    }

    return im;
}


private void performDoubleQRStep(final int il, final int im, final int iu,
                                 final ShiftInfo shift, final double[] hVec) {

    final int n = matrixT.length;
    double p = hVec[0];
    double q = hVec[1];
    double r = hVec[2];

    for (int k = im; k <= iu - 1; k++) {
        boolean notlast = k != (iu - 1);
        if (k != im) {
            p = matrixT[k][k - 1];
            q = matrixT[k + 1][k - 1];
            r = notlast ? matrixT[k + 2][k - 1] : 0.0;
            shift.x = FastMath.abs(p) + FastMath.abs(q) + FastMath.abs(r);
            if (!Precision.equals(shift.x, 0.0, epsilon)) {
                p = p / shift.x;
                q = q / shift.x;
                r = r / shift.x;
            }
        }
        if (shift.x == 0.0) {
            break;
        }
        double s = FastMath.sqrt(p * p + q * q + r * r);
        if (p < 0.0) {
            s = -s;
        }
        if (s != 0.0) {
            if (k != im) {
                matrixT[k][k - 1] = -s * shift.x;
            } else if (il != im) {
                matrixT[k][k - 1] = -matrixT[k][k - 1];
            }
            p = p + s;
            shift.x = p / s;
            shift.y = q / s;
            double z = r / s;
            q = q / p;
            r = r / p;


            for (int j = k; j < n; j++) {
                p = matrixT[k][j] + q * matrixT[k + 1][j];
                if (notlast) {
                    p = p + r * matrixT[k + 2][j];
                    matrixT[k + 2][j] = matrixT[k + 2][j] - p * z;
                }
                matrixT[k][j] = matrixT[k][j] - p * shift.x;
                matrixT[k + 1][j] = matrixT[k + 1][j] - p * shift.y;
            }


            for (int i = 0; i <= FastMath.min(iu, k + 3); i++) {
                p = shift.x * matrixT[i][k] + shift.y * matrixT[i][k + 1];
                if (notlast) {
                    p = p + z * matrixT[i][k + 2];
                    matrixT[i][k + 2] = matrixT[i][k + 2] - p * r;
                }
                matrixT[i][k] = matrixT[i][k] - p;
                matrixT[i][k + 1] = matrixT[i][k + 1] - p * q;
            }


            final int high = matrixT.length - 1;
            for (int i = 0; i <= high; i++) {
                p = shift.x * matrixP[i][k] + shift.y * matrixP[i][k + 1];
                if (notlast) {
                    p = p + z * matrixP[i][k + 2];
                    matrixP[i][k + 2] = matrixP[i][k + 2] - p * r;
                }
                matrixP[i][k] = matrixP[i][k] - p;
                matrixP[i][k + 1] = matrixP[i][k + 1] - p * q;
            }
        }  
    }  


    for (int i = im + 2; i <= iu; i++) {
        matrixT[i][i-2] = 0.0;
        if (i > im + 2) {
            matrixT[i][i-3] = 0.0;
        }
    }
}


private void transform() {
    final int n = matrixT.length;


    final double norm = getNorm();


    final ShiftInfo shift = new ShiftInfo();


    int iteration = 0;
    int iu = n - 1;
    while (iu >= 0) {


        final int il = findSmallSubDiagonalElement(iu, norm);


        if (il == iu) {

            matrixT[iu][iu] = matrixT[iu][iu] + shift.exShift;
            iu--;
            iteration = 0;
        } else if (il == iu - 1) {

            double p = (matrixT[iu - 1][iu - 1] - matrixT[iu][iu]) / 2.0;
            double q = p * p + matrixT[iu][iu - 1] * matrixT[iu - 1][iu];
            matrixT[iu][iu] += shift.exShift;
            matrixT[iu - 1][iu - 1] += shift.exShift;

            if (q >= 0) {
                double z = FastMath.sqrt(FastMath.abs(q));
                if (p >= 0) {
                    z = p + z;
                } else {
                    z = p - z;
                }
                final double x = matrixT[iu][iu - 1];
                final double s = FastMath.abs(x) + FastMath.abs(z);
                p = x / s;
                q = z / s;
                final double r = FastMath.sqrt(p * p + q * q);
                p = p / r;
                q = q / r;


                for (int j = iu - 1; j < n; j++) {
                    z = matrixT[iu - 1][j];
                    matrixT[iu - 1][j] = q * z + p * matrixT[iu][j];
                    matrixT[iu][j] = q * matrixT[iu][j] - p * z;
                }


                for (int i = 0; i <= iu; i++) {
                    z = matrixT[i][iu - 1];
                    matrixT[i][iu - 1] = q * z + p * matrixT[i][iu];
                    matrixT[i][iu] = q * matrixT[i][iu] - p * z;
                }


                for (int i = 0; i <= n - 1; i++) {
                    z = matrixP[i][iu - 1];
                    matrixP[i][iu - 1] = q * z + p * matrixP[i][iu];
                    matrixP[i][iu] = q * matrixP[i][iu] - p * z;
                }
            }
            iu -= 2;
            iteration = 0;
        } else {

            computeShift(il, iu, iteration, shift);


            if (++iteration > MAX_ITERATIONS) {
                throw new MaxCountExceededException(LocalizedFormats.CONVERGENCE_FAILED,
                                                    MAX_ITERATIONS);
            }


            final double[] hVec = new double[3];

            final int im = initQRStep(il, iu, shift, hVec);
            performDoubleQRStep(il, im, iu, shift, hVec);
        }
    }
}


