        final double deltaOne = trustRegionCenterOffset.getEntry(i);
        xoptsq += deltaOne * deltaOne;
    }
    double fsave = fAtInterpolationPoints.getEntry(0);
    final int kbase = 0;



    int ntrits = 0;
    int itest = 0;
    int knew = 0;
    int nfsav = getEvaluations();
    double rho = initialTrustRegionRadius;
    double delta = rho;
    double diffa = ZERO;
    double diffb = ZERO;
    double diffc = ZERO;
    double f = ZERO;
    double beta = ZERO;
    double adelt = ZERO;
    double denom = ZERO;
    double ratio = ZERO;
    double dnorm = ZERO;
    double scaden = ZERO;
    double biglsq = ZERO;
    double distsq = ZERO;




    int state = 20;
    for(;;) switch (state) {
    case 20: {
        printState(20); 
        if (trustRegionCenterInterpolationPointIndex != kbase) {
            int ih = 0;
            for (int j = 0; j < n; j++) {
                for (int i = 0; i <= j; i++) {
                    if (i < j) {
                        gradientAtTrustRegionCenter.setEntry(j, gradientAtTrustRegionCenter.getEntry(j) + modelSecondDerivativesValues.getEntry(ih) * trustRegionCenterOffset.getEntry(i));
                    }
