        if (dnorm < HALF * rho) {
            ntrits = -1;

            deltaOne = TEN * rho;
            distsq = deltaOne * deltaOne;
            if (getEvaluations() <= nfsav + 2) {
                state = 650; break;
            }








            deltaOne = Math.max(diffa, diffb);
            final double errbig = Math.max(deltaOne, diffc);
            final double frhosq = rho * ONE_OVER_EIGHT * rho;
            if (crvmin > ZERO &&
                errbig > frhosq * crvmin) {
