                for (int j = 0; j < n; j++) {

                    final double d3 = interpolationPoints.getEntry(k, j) - trustRegionCenterOffset.getEntry(j);
                    distsq += d3 * d3;
                }


                final double d4 = distsq / delsq;
                final double temp = Math.max(ONE, d4 * d4);
                if (temp * den > scaden) {
                    scaden = temp * den;
                    knew = k;
                    denom = den;
