private double[] basicGuess(WeightedObservedPoint[] points) {
    final int maxYIdx = findMaxY(points);
    final double n = points[maxYIdx].getY();
    final double m = points[maxYIdx].getX();

    double fwhmApprox;
    try {
        final double halfY = n + ((m - n) / 2);
        final double fwhmX1 = interpolateXAtY(points, maxYIdx, -1, halfY);
        final double fwhmX2 = interpolateXAtY(points, maxYIdx, 1, halfY);
        fwhmApprox = fwhmX2 - fwhmX1;
    } catch (OutOfRangeException e) {

        fwhmApprox = points[points.length - 1].getX() - points[0].getX();
    }
    final double s = fwhmApprox / (2 * FastMath.sqrt(2 * FastMath.log(2)));

    return new double[] { n, m, s };
}


private int findMaxY(WeightedObservedPoint[] points) {
    int maxYIdx = 0;
    for (int i = 1; i < points.length; i++) {
        if (points[i].getY() > points[maxYIdx].getY()) {
            maxYIdx = i;
        }
    }
    return maxYIdx;
}


private WeightedObservedPoint[] getInterpolationPointsForY(WeightedObservedPoint[] points,
                                                           int startIdx,
                                                           int idxStep,
                                                           double y)
    throws OutOfRangeException {
    if (idxStep == 0) {
        throw new ZeroException();
    }
    for (int i = startIdx;
         idxStep < 0 ? i + idxStep >= 0 : i + idxStep < points.length;
         i += idxStep) {
        final WeightedObservedPoint p1 = points[i];
        final WeightedObservedPoint p2 = points[i + idxStep];
        if (isBetween(y, p1.getY(), p2.getY())) {
            if (idxStep < 0) {
                return new WeightedObservedPoint[] { p2, p1 };
            } else {
                return new WeightedObservedPoint[] { p1, p2 };
            }
        }
    }




    throw new OutOfRangeException(y,
                                  Double.NEGATIVE_INFINITY,
                                  Double.POSITIVE_INFINITY);
}


private double interpolateXAtY(WeightedObservedPoint[] points,
                               int startIdx,
                               int idxStep,
                               double y)
    throws OutOfRangeException {
    if (idxStep == 0) {
        throw new ZeroException();
    }
    final WeightedObservedPoint[] twoPoints
        = getInterpolationPointsForY(points, startIdx, idxStep, y);
    final WeightedObservedPoint p1 = twoPoints[0];
    final WeightedObservedPoint p2 = twoPoints[1];
    if (p1.getY() == y) {
        return p1.getX();
    }
    if (p2.getY() == y) {
        return p2.getX();
    }
    return p1.getX() + (((y - p1.getY()) * (p2.getX() - p1.getX())) /
                        (p2.getY() - p1.getY()));
}


private boolean isBetween(double value,
                          double boundary1,
                          double boundary2) {
    return (value >= boundary1 && value <= boundary2) ||
        (value >= boundary2 && value <= boundary1);
}


private WeightedObservedPoint[] sortObservations(WeightedObservedPoint[] unsorted) {
    final WeightedObservedPoint[] observations = unsorted.clone();
    final Comparator<WeightedObservedPoint> cmp
        = new Comparator<WeightedObservedPoint>() {
        public int compare(WeightedObservedPoint p1,
                           WeightedObservedPoint p2) {
            if (p1 == null && p2 == null) {
                return 0;
            }
            if (p1 == null) {
                return -1;
            }
            if (p2 == null) {
                return 1;
            }
            if (p1.getX() < p2.getX()) {
                return -1;
            }
            if (p1.getX() > p2.getX()) {
                return 1;
            }
            if (p1.getY() < p2.getY()) {
                return -1;
            }
            if (p1.getY() > p2.getY()) {
                return 1;
            }
            if (p1.getWeight() < p2.getWeight()) {
                return -1;
            }
            if (p1.getWeight() > p2.getWeight()) {
                return 1;
            }
            return 0;
        }
    };

    Arrays.sort(observations, cmp);
    return observations;
}


private double[] guessAOmega(WeightedObservedPoint[] observations) {
    final double[] aOmega = new double[2];


    double sx2 = 0;
    double sy2 = 0;
    double sxy = 0;
    double sxz = 0;
    double syz = 0;

    double currentX = observations[0].getX();
    double currentY = observations[0].getY();
    double f2Integral = 0;
    double fPrime2Integral = 0;
    final double startX = currentX;
    for (int i = 1; i < observations.length; ++i) {

        final double previousX = currentX;
        final double previousY = currentY;
        currentX = observations[i].getX();
        currentY = observations[i].getY();



        final double dx = currentX - previousX;
        final double dy = currentY - previousY;
        final double f2StepIntegral =
            dx * (previousY * previousY + previousY * currentY + currentY * currentY) / 3;
        final double fPrime2StepIntegral = dy * dy / dx;

        final double x = currentX - startX;
        f2Integral += f2StepIntegral;
        fPrime2Integral += fPrime2StepIntegral;

        sx2 += x * x;
        sy2 += f2Integral * f2Integral;
        sxy += x * f2Integral;
        sxz += x * fPrime2Integral;
        syz += f2Integral * fPrime2Integral;
    }


    double c1 = sy2 * sxz - sxy * syz;
    double c2 = sxy * sxz - sx2 * syz;
    double c3 = sx2 * sy2 - sxy * sxy;
    if ((c1 / c2 < 0) || (c2 / c3 < 0)) {
        final int last = observations.length - 1;


        final double xRange = observations[last].getX() - observations[0].getX();
        if (xRange == 0) {
            throw new ZeroException();
        }
        aOmega[1] = 2 * Math.PI / xRange;

        double yMin = Double.POSITIVE_INFINITY;
        double yMax = Double.NEGATIVE_INFINITY;
        for (int i = 1; i < observations.length; ++i) {
            final double y = observations[i].getY();
            if (y < yMin) {
                yMin = y;
            }
            if (y > yMax) {
                yMax = y;
            }
        }
        aOmega[0] = 0.5 * (yMax - yMin);
    } else {
        if (c2 == 0) {


            throw new MathIllegalStateException(LocalizedFormats.ZERO_DENOMINATOR);
        }

        aOmega[0] = FastMath.sqrt(c1 / c2);
        aOmega[1] = FastMath.sqrt(c2 / c3);
    }

    return aOmega;
}


private double guessPhi(WeightedObservedPoint[] observations) {

    double fcMean = 0;
    double fsMean = 0;

    double currentX = observations[0].getX();
    double currentY = observations[0].getY();
    for (int i = 1; i < observations.length; ++i) {

        final double previousX = currentX;
        final double previousY = currentY;
        currentX = observations[i].getX();
        currentY = observations[i].getY();
        final double currentYPrime = (currentY - previousY) / (currentX - previousX);

        double omegaX = omega * currentX;
        double cosine = FastMath.cos(omegaX);
        double sine = FastMath.sin(omegaX);
        fcMean += omega * currentY * cosine - currentYPrime * sine;
        fsMean += omega * currentY * sine + currentYPrime * cosine;
    }

    return FastMath.atan2(-fsMean, fcMean);
}


private WeightedObservedPoint[] sortObservations(WeightedObservedPoint[] unsorted) {
    final WeightedObservedPoint[] observations = unsorted.clone();




    WeightedObservedPoint curr = observations[0];
    for (int j = 1; j < observations.length; ++j) {
        WeightedObservedPoint prec = curr;
        curr = observations[j];
        if (curr.getX() < prec.getX()) {

            int i = j - 1;
            WeightedObservedPoint mI = observations[i];
            while ((i >= 0) && (curr.getX() < mI.getX())) {
                observations[i + 1] = mI;
                if (i-- != 0) {
                    mI = observations[i];
                }
            }
            observations[i + 1] = curr;
            curr = observations[j];
        }
    }

    return observations;
}


private RealMatrix squareRoot(RealMatrix m) {
    if (m instanceof DiagonalMatrix) {
        final int dim = m.getRowDimension();
        final RealMatrix sqrtM = new DiagonalMatrix(dim);
        for (int i = 0; i < dim; i++) {
           sqrtM.setEntry(i, i, FastMath.sqrt(m.getEntry(i, i)));
        }
        return sqrtM;
    } else {
        final EigenDecomposition dec = new EigenDecomposition(m);
        return dec.getSquareRoot();
    }
}


private void determineLMDirection(double[] qy, double[] diag,
                                  double[] lmDiag, double[] work) {



    for (int j = 0; j < solvedCols; ++j) {
        int pj = permutation[j];
        for (int i = j + 1; i < solvedCols; ++i) {
            weightedJacobian[i][pj] = weightedJacobian[j][permutation[i]];
        }
        lmDir[j] = diagR[pj];
        work[j]  = qy[j];
    }


    for (int j = 0; j < solvedCols; ++j) {



        int pj = permutation[j];
        double dpj = diag[pj];
        if (dpj != 0) {
            Arrays.fill(lmDiag, j + 1, lmDiag.length, 0);
        }
        lmDiag[j] = dpj;




        double qtbpj = 0;
        for (int k = j; k < solvedCols; ++k) {
            int pk = permutation[k];



            if (lmDiag[k] != 0) {

                final double sin;
                final double cos;
                double rkk = weightedJacobian[k][pk];
                if (FastMath.abs(rkk) < FastMath.abs(lmDiag[k])) {
                    final double cotan = rkk / lmDiag[k];
                    sin   = 1.0 / FastMath.sqrt(1.0 + cotan * cotan);
                    cos   = sin * cotan;
                } else {
                    final double tan = lmDiag[k] / rkk;
                    cos = 1.0 / FastMath.sqrt(1.0 + tan * tan);
                    sin = cos * tan;
                }



                weightedJacobian[k][pk] = cos * rkk + sin * lmDiag[k];
                final double temp = cos * work[k] + sin * qtbpj;
                qtbpj = -sin * work[k] + cos * qtbpj;
                work[k] = temp;


                for (int i = k + 1; i < solvedCols; ++i) {
                    double rik = weightedJacobian[i][pk];
                    final double temp2 = cos * rik + sin * lmDiag[i];
                    lmDiag[i] = -sin * rik + cos * lmDiag[i];
                    weightedJacobian[i][pk] = temp2;
                }
            }
        }



        lmDiag[j] = weightedJacobian[j][permutation[j]];
        weightedJacobian[j][permutation[j]] = lmDir[j];
    }



    int nSing = solvedCols;
    for (int j = 0; j < solvedCols; ++j) {
        if ((lmDiag[j] == 0) && (nSing == solvedCols)) {
            nSing = j;
        }
        if (nSing < solvedCols) {
            work[j] = 0;
        }
    }
    if (nSing > 0) {
        for (int j = nSing - 1; j >= 0; --j) {
            int pj = permutation[j];
            double sum = 0;
            for (int i = j + 1; i < nSing; ++i) {
                sum += weightedJacobian[i][pj] * work[i];
            }
            work[j] = (work[j] - sum) / lmDiag[j];
        }
    }


    for (int j = 0; j < lmDir.length; ++j) {
        lmDir[permutation[j]] = work[j];
    }
}


private void determineLMParameter(double[] qy, double delta, double[] diag,
                                  double[] work1, double[] work2, double[] work3) {
    final int nC = weightedJacobian[0].length;



    for (int j = 0; j < rank; ++j) {
        lmDir[permutation[j]] = qy[j];
    }
    for (int j = rank; j < nC; ++j) {
        lmDir[permutation[j]] = 0;
    }
    for (int k = rank - 1; k >= 0; --k) {
        int pk = permutation[k];
        double ypk = lmDir[pk] / diagR[pk];
        for (int i = 0; i < k; ++i) {
            lmDir[permutation[i]] -= ypk * weightedJacobian[i][pk];
        }
        lmDir[pk] = ypk;
    }



    double dxNorm = 0;
    for (int j = 0; j < solvedCols; ++j) {
        int pj = permutation[j];
        double s = diag[pj] * lmDir[pj];
        work1[pj] = s;
        dxNorm += s * s;
    }
    dxNorm = FastMath.sqrt(dxNorm);
    double fp = dxNorm - delta;
    if (fp <= 0.1 * delta) {
        lmPar = 0;
        return;
    }




    double sum2;
    double parl = 0;
    if (rank == solvedCols) {
        for (int j = 0; j < solvedCols; ++j) {
            int pj = permutation[j];
            work1[pj] *= diag[pj] / dxNorm;
        }
        sum2 = 0;
        for (int j = 0; j < solvedCols; ++j) {
            int pj = permutation[j];
            double sum = 0;
            for (int i = 0; i < j; ++i) {
                sum += weightedJacobian[i][pj] * work1[permutation[i]];
            }
            double s = (work1[pj] - sum) / diagR[pj];
            work1[pj] = s;
            sum2 += s * s;
        }
        parl = fp / (delta * sum2);
    }


    sum2 = 0;
    for (int j = 0; j < solvedCols; ++j) {
        int pj = permutation[j];
        double sum = 0;
        for (int i = 0; i <= j; ++i) {
            sum += weightedJacobian[i][pj] * qy[i];
        }
        sum /= diag[pj];
        sum2 += sum * sum;
    }
    double gNorm = FastMath.sqrt(sum2);
    double paru = gNorm / delta;
    if (paru == 0) {

        paru = 2.2251e-308 / FastMath.min(delta, 0.1);
    }



    lmPar = FastMath.min(paru, FastMath.max(lmPar, parl));
    if (lmPar == 0) {
        lmPar = gNorm / dxNorm;
    }

    for (int countdown = 10; countdown >= 0; --countdown) {


        if (lmPar == 0) {
            lmPar = FastMath.max(2.2251e-308, 0.001 * paru);
        }
        double sPar = FastMath.sqrt(lmPar);
        for (int j = 0; j < solvedCols; ++j) {
            int pj = permutation[j];
            work1[pj] = sPar * diag[pj];
        }
        determineLMDirection(qy, work1, work2, work3);

        dxNorm = 0;
        for (int j = 0; j < solvedCols; ++j) {
            int pj = permutation[j];
            double s = diag[pj] * lmDir[pj];
            work3[pj] = s;
            dxNorm += s * s;
        }
        dxNorm = FastMath.sqrt(dxNorm);
        double previousFP = fp;
        fp = dxNorm - delta;



        if ((FastMath.abs(fp) <= 0.1 * delta) ||
                ((parl == 0) && (fp <= previousFP) && (previousFP < 0))) {
            return;
        }


        for (int j = 0; j < solvedCols; ++j) {
            int pj = permutation[j];
            work1[pj] = work3[pj] * diag[pj] / dxNorm;
        }
        for (int j = 0; j < solvedCols; ++j) {
            int pj = permutation[j];
            work1[pj] /= work2[j];
            double tmp = work1[pj];
            for (int i = j + 1; i < solvedCols; ++i) {
                work1[permutation[i]] -= weightedJacobian[i][pj] * tmp;
            }
        }
        sum2 = 0;
        for (int j = 0; j < solvedCols; ++j) {
            double s = work1[permutation[j]];
            sum2 += s * s;
        }
        double correction = fp / (delta * sum2);


        if (fp > 0) {
            parl = FastMath.max(parl, lmPar);
        } else if (fp < 0) {
            paru = FastMath.min(paru, lmPar);
        }


        lmPar = FastMath.max(parl, lmPar + correction);

    }
}


private void qTy(double[] y) {
    final int nR = weightedJacobian.length;
    final int nC = weightedJacobian[0].length;

    for (int k = 0; k < nC; ++k) {
        int pk = permutation[k];
        double gamma = 0;
        for (int i = k; i < nR; ++i) {
            gamma += weightedJacobian[i][pk] * y[i];
        }
        gamma *= beta[pk];
        for (int i = k; i < nR; ++i) {
            y[i] -= gamma * weightedJacobian[i][pk];
        }
    }
}


private void qrDecomposition(RealMatrix jacobian) throws ConvergenceException {


    weightedJacobian = jacobian.scalarMultiply(-1).getData();

    final int nR = weightedJacobian.length;
    final int nC = weightedJacobian[0].length;


    for (int k = 0; k < nC; ++k) {
        permutation[k] = k;
        double norm2 = 0;
        for (int i = 0; i < nR; ++i) {
            double akk = weightedJacobian[i][k];
            norm2 += akk * akk;
        }
        jacNorm[k] = FastMath.sqrt(norm2);
    }


    for (int k = 0; k < nC; ++k) {


        int nextColumn = -1;
        double ak2 = Double.NEGATIVE_INFINITY;
        for (int i = k; i < nC; ++i) {
            double norm2 = 0;
            for (int j = k; j < nR; ++j) {
                double aki = weightedJacobian[j][permutation[i]];
                norm2 += aki * aki;
            }
            if (Double.isInfinite(norm2) || Double.isNaN(norm2)) {
                throw new ConvergenceException(LocalizedFormats.UNABLE_TO_PERFORM_QR_DECOMPOSITION_ON_JACOBIAN,
                                               nR, nC);
            }
            if (norm2 > ak2) {
                nextColumn = i;
                ak2        = norm2;
            }
        }
        if (ak2 <= qrRankingThreshold) {
            rank = k;
            return;
        }
        int pk                  = permutation[nextColumn];
        permutation[nextColumn] = permutation[k];
        permutation[k]          = pk;


        double akk   = weightedJacobian[k][pk];
        double alpha = (akk > 0) ? -FastMath.sqrt(ak2) : FastMath.sqrt(ak2);
        double betak = 1.0 / (ak2 - akk * alpha);
        beta[pk]     = betak;


        diagR[pk]        = alpha;
        weightedJacobian[k][pk] -= alpha;


        for (int dk = nC - 1 - k; dk > 0; --dk) {
            double gamma = 0;
            for (int j = k; j < nR; ++j) {
                gamma += weightedJacobian[j][pk] * weightedJacobian[j][permutation[k + dk]];
            }
            gamma *= betak;
            for (int j = k; j < nR; ++j) {
                weightedJacobian[j][permutation[k + dk]] -= gamma * weightedJacobian[j][pk];
            }
        }
    }
    rank = solvedCols;
}


private double findUpperBound(final UnivariateFunction f,
                              final double a, final double h) {
    final double yA = f.value(a);
    double yB = yA;
    for (double step = h; step < Double.MAX_VALUE; step *= FastMath.max(2, yA / yB)) {
        final double b = a + step;
        yB = f.value(b);
        if (yA * yB <= 0) {
            return b;
        }
    }
    throw new MathIllegalStateException(LocalizedFormats.UNABLE_TO_BRACKET_OPTIMUM_IN_LINE_SEARCH);
}


private Integer getPivotColumn(SimplexTableau tableau) {
    double minValue = 0;
    Integer minPos = null;
    for (int i = tableau.getNumObjectiveFunctions(); i < tableau.getWidth() - 1; i++) {
        final double entry = tableau.getEntry(0, i);


        if (entry < minValue) {
            minValue = entry;
            minPos = i;
        }
    }
    return minPos;
}


private Integer getPivotRow(SimplexTableau tableau, final int col) {

    List<Integer> minRatioPositions = new ArrayList<Integer>();
    double minRatio = Double.MAX_VALUE;
    for (int i = tableau.getNumObjectiveFunctions(); i < tableau.getHeight(); i++) {
        final double rhs = tableau.getEntry(i, tableau.getWidth() - 1);
        final double entry = tableau.getEntry(i, col);

        if (Precision.compareTo(entry, 0d, maxUlps) > 0) {
            final double ratio = rhs / entry;


            final int cmp = Double.compare(ratio, minRatio);
            if (cmp == 0) {
                minRatioPositions.add(i);
            } else if (cmp < 0) {
                minRatio = ratio;
                minRatioPositions = new ArrayList<Integer>();
                minRatioPositions.add(i);
            }
        }
    }

    if (minRatioPositions.size() == 0) {
        return null;
    } else if (minRatioPositions.size() > 1) {



        if (tableau.getNumArtificialVariables() > 0) {
            for (Integer row : minRatioPositions) {
                for (int i = 0; i < tableau.getNumArtificialVariables(); i++) {
                    int column = i + tableau.getArtificialVariableOffset();
                    final double entry = tableau.getEntry(row, column);
                    if (Precision.equals(entry, 1d, maxUlps) && row.equals(tableau.getBasicRow(column))) {
                        return row;
                    }
                }
            }
        }










        if (getIterations() < getMaxIterations() / 2) {
            Integer minRow = null;
            int minIndex = tableau.getWidth();
            final int varStart = tableau.getNumObjectiveFunctions();
            final int varEnd = tableau.getWidth() - 1;
            for (Integer row : minRatioPositions) {
                for (int i = varStart; i < varEnd && !row.equals(minRow); i++) {
                    final Integer basicRow = tableau.getBasicRow(i);
                    if (basicRow != null && basicRow.equals(row)) {
                        if (i < minIndex) {
                            minIndex = i;
                            minRow = row;
                        }
                    }
                }
            }
            return minRow;
        }
    }
    return minRatioPositions.get(0);
}


private void copyArray(final double[] src, final double[] dest) {
    System.arraycopy(src, 0, dest, getNumObjectiveFunctions(), src.length);
}


private int getConstraintTypeCounts(final Relationship relationship) {
    int count = 0;
    for (final LinearConstraint constraint : constraints) {
        if (constraint.getRelationship() == relationship) {
            ++count;
        }
    }
    return count;
}


private LinearConstraint normalize(final LinearConstraint constraint) {
    if (constraint.getValue() < 0) {
        return new LinearConstraint(constraint.getCoefficients().mapMultiply(-1),
                                    constraint.getRelationship().oppositeRelationship(),
                                    -1 * constraint.getValue());
    }
    return new LinearConstraint(constraint.getCoefficients(),
                                constraint.getRelationship(), constraint.getValue());
}


private double eval(UnivariateFunction f, double x) {
    try {
        evaluations.incrementCount();
    } catch (MaxCountExceededException e) {
        throw new TooManyEvaluationsException(e.getMax());
    }
    return f.value(x);
}


private UnivariatePointValuePair best(UnivariatePointValuePair a,
                                      UnivariatePointValuePair b,
                                      boolean isMinim) {
    if (a == null) {
        return b;
    }
    if (b == null) {
        return a;
    }

    if (isMinim) {
        return a.getValue() <= b.getValue() ? a : b;
    } else {
        return a.getValue() >= b.getValue() ? a : b;
    }
}


private void sortPairs(final GoalType goal) {
    Arrays.sort(optima, new Comparator<UnivariatePointValuePair>() {
            public int compare(final UnivariatePointValuePair o1,
                               final UnivariatePointValuePair o2) {
                if (o1 == null) {
                    return (o2 == null) ? 0 : 1;
                } else if (o2 == null) {
                    return -1;
                }
                final double v1 = o1.getValue();
                final double v2 = o2.getValue();
                return (goal == GoalType.MINIMIZE) ?
                    Double.compare(v1, v2) : Double.compare(v2, v1);
            }
        });
}


private double cumBinP(int binIndex) {
    return upperBounds[binIndex];
}


private void fillBinStats(final DataAdapter da)
    throws IOException {

    min = sampleStats.getMin();
    max = sampleStats.getMax();
    delta = (max - min)/(Double.valueOf(binCount)).doubleValue();


    if (!binStats.isEmpty()) {
        binStats.clear();
    }
    for (int i = 0; i < binCount; i++) {
        SummaryStatistics stats = new SummaryStatistics();
        binStats.add(i,stats);
    }


    da.computeBinStats();


    upperBounds = new double[binCount];
    upperBounds[0] =
    ((double) binStats.get(0).getN()) / (double) sampleStats.getN();
    for (int i = 1; i < binCount-1; i++) {
        upperBounds[i] = upperBounds[i-1] +
        ((double) binStats.get(i).getN()) / (double) sampleStats.getN();
    }
    upperBounds[binCount-1] = 1.0d;
}


private int findBin(double value) {
    return FastMath.min(
            FastMath.max((int) FastMath.ceil((value - min) / delta) - 1, 0),
            binCount - 1);
}


private RealDistribution k(double x) {
    final int binIndex = findBin(x);
    return getKernel(binStats.get(binIndex));
}

private double kB(int i) {
    final double[] binBounds = getUpperBounds();
    final RealDistribution kernel = getKernel(binStats.get(i));
    return i == 0 ? kernel.cumulativeProbability(min, binBounds[0]) :
        kernel.cumulativeProbability(binBounds[i - 1], binBounds[i]);
}


private double pB(int i) {
    return i == 0 ? upperBounds[0] :
        upperBounds[i] - upperBounds[i - 1];
}


private double pBminus(int i) {
    return i == 0 ? 0 : upperBounds[i - 1];
}


