        arr[7] += mem[j + 7];
        shuffle();
        setState(j);
    }
    isaac();
    count = SIZE - 1;
    clear();
}


private void isaac() {
    isaacI = 0;
    isaacJ = H_SIZE;
    isaacB += ++isaacC;
    while (isaacI < H_SIZE) {
        isaac2();
    }
    isaacJ = 0;
    while (isaacJ < H_SIZE) {
        isaac2();
    }
}


private void isaac2() {
    isaacX = mem[isaacI];
    isaacA ^= isaacA << 13;
    isaacA += mem[isaacJ++];
    isaac3();
    isaacX = mem[isaacI];
    isaacA ^= isaacA >>> 6;
    isaacA += mem[isaacJ++];
    isaac3();
    isaacX = mem[isaacI];
    isaacA ^= isaacA << 2;
    isaacA += mem[isaacJ++];
    isaac3();
    isaacX = mem[isaacI];
    isaacA ^= isaacA >>> 16;
    isaacA += mem[isaacJ++];
    isaac3();
}


private void isaac3() {
    mem[isaacI] = mem[(isaacX & MASK) >> 2] + isaacA + isaacB;
    isaacB = mem[(mem[isaacI] >> SIZE_L & MASK) >> 2] + isaacX;
    rsl[isaacI++] = isaacB;
}


