public Object mdfft(Object mdca, TransformType type) {
    MultiDimensionalComplexMatrix mdcm = (MultiDimensionalComplexMatrix)
            new MultiDimensionalComplexMatrix(mdca).clone();
    int[] dimensionSize = mdcm.getDimensionSizes();

    for (int i = 0; i < dimensionSize.length; i++) {
        mdfft(mdcm, type, i, new int[0]);
    }
    return mdcm.getArray();
}


public boolean containsKey(final int key) {

    final int hash  = hashOf(key);
    int index = hash & mask;
    if (containsKey(key, index)) {
        return true;
    }

    if (states[index] == FREE) {
        return false;
    }

    int j = index;
    for (int perturb = perturb(hash); states[index] != FREE; perturb >>= PERTURB_SHIFT) {
        j = probe(perturb, j);
        index = j & mask;
        if (containsKey(key, index)) {
            return true;
        }
    }

    return false;

}


private double doRemove(int index) {
    keys[index]   = 0;
    states[index] = REMOVED;
    final double previous = values[index];
    values[index] = missingEntries;
    --size;
    ++count;
    return previous;
}


private int findInsertionIndex(final int key) {
    return findInsertionIndex(keys, states, key, mask);
}


private void growTable() {

    final int oldLength      = states.length;
    final int[] oldKeys      = keys;
    final double[] oldValues = values;
    final byte[] oldStates   = states;

    final int newLength = RESIZE_MULTIPLIER * oldLength;
    final int[] newKeys = new int[newLength];
    final double[] newValues = new double[newLength];
    final byte[] newStates = new byte[newLength];
    final int newMask = newLength - 1;
    for (int i = 0; i < oldLength; ++i) {
        if (oldStates[i] == FULL) {
            final int key = oldKeys[i];
            final int index = findInsertionIndex(newKeys, newStates, key, newMask);
            newKeys[index]   = key;
            newValues[index] = oldValues[i];
            newStates[index] = FULL;
        }
    }

    mask   = newMask;
    keys   = newKeys;
    values = newValues;
    states = newStates;

}


private boolean shouldGrowTable() {
    return size > (mask + 1) * LOAD_FACTOR;
}

private T[] buildArray(final int length) {
    return (T[]) Array.newInstance(field.getRuntimeClass(), length);
}


public boolean containsKey(final int key) {

    final int hash  = hashOf(key);
    int index = hash & mask;
    if (containsKey(key, index)) {
        return true;
    }

    if (states[index] == FREE) {
        return false;
    }

    int j = index;
    for (int perturb = perturb(hash); states[index] != FREE; perturb >>= PERTURB_SHIFT) {
        j = probe(perturb, j);
        index = j & mask;
        if (containsKey(key, index)) {
            return true;
        }
    }

    return false;

}


private T doRemove(int index) {
    keys[index]   = 0;
    states[index] = REMOVED;
    final T previous = values[index];
    values[index] = missingEntries;
    --size;
    ++count;
    return previous;
}


private int findInsertionIndex(final int key) {
    return findInsertionIndex(keys, states, key, mask);
}


private void growTable() {

    final int oldLength      = states.length;
    final int[] oldKeys      = keys;
    final T[] oldValues = values;
    final byte[] oldStates   = states;

    final int newLength = RESIZE_MULTIPLIER * oldLength;
    final int[] newKeys = new int[newLength];
    final T[] newValues = buildArray(newLength);
    final byte[] newStates = new byte[newLength];
    final int newMask = newLength - 1;
    for (int i = 0; i < oldLength; ++i) {
        if (oldStates[i] == FULL) {
            final int key = oldKeys[i];
            final int index = findInsertionIndex(newKeys, newStates, key, newMask);
            newKeys[index]   = key;
            newValues[index] = oldValues[i];
            newStates[index] = FULL;
        }
    }

    mask   = newMask;
    keys   = newKeys;
    values = newValues;
    states = newStates;

}


private boolean shouldGrowTable() {
    return size > (mask + 1) * LOAD_FACTOR;
}


private synchronized void discardExtremeElements(int i,
                                                 boolean front)
    throws MathIllegalArgumentException {
    if (i > numElements) {
        throw new MathIllegalArgumentException(
                LocalizedFormats.TOO_MANY_ELEMENTS_TO_DISCARD_FROM_ARRAY,
                i, numElements);
   } else if (i < 0) {
       throw new MathIllegalArgumentException(
               LocalizedFormats.CANNOT_DISCARD_NEGATIVE_NUMBER_OF_ELEMENTS,
               i);
    } else {

        numElements -= i;
        if (front) {
            startIndex += i;
        }
    }
    if (shouldContract()) {
        contract();
    }
}


private synchronized void expandTo(int size) {
    final double[] tempArray = new double[size];

    System.arraycopy(internalArray, 0, tempArray, 0, internalArray.length);
    internalArray = tempArray;
}


private synchronized boolean shouldContract() {
    if (expansionMode == ExpansionMode.MULTIPLICATIVE) {
        return (internalArray.length / ((float) numElements)) > contractionCriterion;
    } else {
        return (internalArray.length - numElements) > contractionCriterion;
    }
}


public static MultivariateFunction collector(final BivariateFunction combiner,
                                             final UnivariateFunction f,
                                             final double initialValue) {
    return new MultivariateFunction() {

        public double value(double[] point) {
            double result = combiner.value(initialValue, f.value(point[0]));
            for (int i = 1; i < point.length; i++) {
                result = combiner.value(result, f.value(point[i]));
            }
            return result;
        }
    };
}


public static UnivariateFunction fix2ndArgument(final BivariateFunction f,
                                                final double fixed) {
