public static double varianceDifference(final double[] sample1,
        final double[] sample2, double meanDifference) throws DimensionMismatchException,
        NumberIsTooSmallException {
    double sum1 = 0d;
    double sum2 = 0d;
    double diff = 0d;
    int n = sample1.length;
    if (n != sample2.length) {
        throw new DimensionMismatchException(n, sample2.length);
    }
    if (n < 2) {
        throw new NumberIsTooSmallException(n, 2, true);
    }
    for (int i = 0; i < n; i++) {
        diff = sample1[i] - sample2[i];
        sum1 += (diff - meanDifference) *(diff - meanDifference);
        sum2 += diff - meanDifference;
    }
    return (sum1 - (sum2 * sum2 / n)) / (n - 1);
}


private static <T extends Clusterable<T>> int
    assignPointsToClusters(final List<Cluster<T>> clusters, final Collection<T> points,
                           final int[] assignments) {
    int assignedDifferently = 0;
    int pointIndex = 0;
    for (final T p : points) {
        int clusterIndex = getNearestCluster(clusters, p);
        if (clusterIndex != assignments[pointIndex]) {
            assignedDifferently++;
        }

        Cluster<T> cluster = clusters.get(clusterIndex);
        cluster.addPoint(p);
        assignments[pointIndex++] = clusterIndex;
    }

    return assignedDifferently;
}


private static <T extends Clusterable<T>> List<Cluster<T>>
    chooseInitialCenters(final Collection<T> points, final int k, final Random random) {



    final List<T> pointList = Collections.unmodifiableList(new ArrayList<T> (points));


    final int numPoints = pointList.size();



    final boolean[] taken = new boolean[numPoints];


    final List<Cluster<T>> resultSet = new ArrayList<Cluster<T>>();


    final int firstPointIndex = random.nextInt(numPoints);

    final T firstPoint = pointList.get(firstPointIndex);

    resultSet.add(new Cluster<T>(firstPoint));


    taken[firstPointIndex] = true;



    final double[] minDistSquared = new double[numPoints];



    for (int i = 0; i < numPoints; i++) {
        if (i != firstPointIndex) { 
            double d = firstPoint.distanceFrom(pointList.get(i));
            minDistSquared[i] = d*d;
        }
    }

    while (resultSet.size() < k) {



        double distSqSum = 0.0;

        for (int i = 0; i < numPoints; i++) {
            if (!taken[i]) {
                distSqSum += minDistSquared[i];
            }
        }



        final double r = random.nextDouble() * distSqSum;


        int nextPointIndex = -1;



        double sum = 0.0;
        for (int i = 0; i < numPoints; i++) {
            if (!taken[i]) {
                sum += minDistSquared[i];
                if (sum >= r) {
                    nextPointIndex = i;
                    break;
                }
            }
        }




        if (nextPointIndex == -1) {
            for (int i = numPoints - 1; i >= 0; i--) {
                if (!taken[i]) {
                    nextPointIndex = i;
                    break;
                }
            }
        }


        if (nextPointIndex >= 0) {

            final T p = pointList.get(nextPointIndex);

            resultSet.add(new Cluster<T> (p));


            taken[nextPointIndex] = true;

            if (resultSet.size() < k) {


                for (int j = 0; j < numPoints; j++) {

                    if (!taken[j]) {
                        double d = p.distanceFrom(pointList.get(j));
                        double d2 = d * d;
                        if (d2 < minDistSquared[j]) {
                            minDistSquared[j] = d2;
                        }
                    }
                }
            }

        } else {



            break;
        }
    }

    return resultSet;
}


private static <T extends Clusterable<T>> int
    getNearestCluster(final Collection<Cluster<T>> clusters, final T point) {
    double minDistance = Double.MAX_VALUE;
    int clusterIndex = 0;
    int minCluster = 0;
    for (final Cluster<T> c : clusters) {
        final double distance = point.distanceFrom(c.getCenter());
        if (distance < minDistance) {
            minDistance = distance;
            minCluster = clusterIndex;
        }
        clusterIndex++;
    }
    return minCluster;
}


