        throw new DimensionMismatchException(dataI.length, dataR.length);
    }

    final int n = dataR.length;
    final Complex[] c = new Complex[n];
    for (int i = 0; i < n; i++) {
        c[i] = new Complex(dataR[i], dataI[i]);
    }
    return c;
}


