public static double acos(double x) {
  if (x != x) {
      return Double.NaN;
  }

  if (x > 1.0 || x < -1.0) {
      return Double.NaN;
  }

  if (x == -1.0) {
      return Math.PI;
  }

  if (x == 1.0) {
      return 0.0;
  }

  if (x == 0) {
      return Math.PI/2.0;
  }




  double temp = x * HEX_40000000;
  final double xa = x + temp - temp;
  final double xb = x - xa;


  double ya = xa*xa;
  double yb = xa*xb*2.0 + xb*xb;


  ya = -ya;
  yb = -yb;

  double za = 1.0 + ya;
  double zb = -(za - 1.0 - ya);

  temp = za + yb;
  zb += -(temp - za - yb);
  za = temp;


  double y = sqrt(za);
  temp = y * HEX_40000000;
  ya = y + temp - temp;
  yb = y - ya;


  yb += (za - ya*ya - 2*ya*yb - yb*yb) / (2.0*y);


  yb += zb / (2.0*y);
  y = ya+yb;
  yb = -(y - ya - yb);


  double r = y/x;


  if (Double.isInfinite(r)) { 
      return Math.PI/2; 
  }

  double ra = doubleHighPart(r);
  double rb = r - ra;

  rb += (y - ra*xa - ra*xb - rb*xa - rb*xb) / x;  
  rb += yb / x;  

  temp = ra + rb;
  rb = -(temp - ra - rb);
  ra = temp;

  return atan(ra, rb, x<0);
}


