      return Double.NaN;
  }

  if (x == 1.0) {
      return Math.PI/2.0;
  }

  if (x == -1.0) {
      return -Math.PI/2.0;
  }

  if (x == 0.0) { 
      return x;
  }




  double temp = x * HEX_40000000;
  final double xa = x + temp - temp;
  final double xb = x - xa;


  double ya = xa*xa;
  double yb = xa*xb*2.0 + xb*xb;


  ya = -ya;
  yb = -yb;

  double za = 1.0 + ya;
  double zb = -(za - 1.0 - ya);

  temp = za + yb;
  zb += -(temp - za - yb);
