    int shift = exponent - (idx << 6);

    if (shift != 0) {
        shpi0 = (idx == 0) ? 0 : (RECIP_2PI[idx-1] << shift);
        shpi0 |= RECIP_2PI[idx] >>> (64-shift);
        shpiA = (RECIP_2PI[idx] << shift) | (RECIP_2PI[idx+1] >>> (64-shift));
