    }


    final double facta = 57.2957763671875;
    final double factb = 3.145894820876798E-6;

    double xa = doubleHighPart(x);
    double xb = x - xa;

    return xb * factb + xb * facta + xa * factb + xa * facta;
}


public static double toRadians(double x)
{
