        return x;
    }


    final double facta = 0.01745329052209854;
    final double factb = 1.997844754509471E-9;

    double xa = doubleHighPart(x);
    double xb = x - xa;

    double result = xb * factb + xb * facta + xa * factb + xa * facta;
    if (result == 0) {
