    split(b[1], ys);
    splitMult(xs, ys, zs);

    double tmp = result[0] + zs[0];
    result[1] = result[1] - (tmp - result[0] - zs[0]);
    result[0] = tmp;
    tmp = result[0] + zs[1];
    result[1] = result[1] - (tmp - result[0] - zs[1]);
    result[0] = tmp;


