    if (c < 8e298 && c > -8e298) { 
        double z = c * HEX_40000000;
        a[0] = (c + z) - z;
        a[1] = c - a[0] + d;
    } else {
        double z = c * 9.31322574615478515625E-10;
        a[0] = (c + z - c) * HEX_40000000;
        a[1] = c - a[0] + d;
    }
}


static double slowCos(final double x, final double result[]) {

