    for (int i = FACT.length-1; i >= 0; i--) {
        splitMult(xs, ys, as);
        ys[0] = as[0]; ys[1] = as[1];

        if ( (i & 1) != 0) { 
            continue;
        }

        split(FACT[i], as);
        splitReciprocal(as, facts);

        if ( (i & 2) != 0 ) { 
            facts[0] = -facts[0];
            facts[1] = -facts[1];
        }

        splitAdd(ys, facts, as);
        ys[0] = as[0]; ys[1] = as[1];
