    result[0] = a / in[0];
    result[1] = (b*in[0]-a*in[1]) / (in[0]*in[0] + in[0]*in[1]);

    if (result[1] != result[1]) { 
        result[1] = 0.0;
    }


    resplit(result);

    for (int i = 0; i < 2; i++) {

        double err = 1.0 - result[0] * in[0] - result[0] * in[1] -
        result[1] * in[0] - result[1] * in[1];

        err = err * (result[0] + result[1]);

        result[1] += err;
    }
