        if ((iterations.getCount() + 1 >= getMinimalIterationCount()) && (delta <= limit)) {
            return t;
        }


        double ratio = FastMath.min(4, FastMath.pow(delta / limit, 0.5 / abscissas.length));
        n = FastMath.max((int) (ratio * n), n + 1);
        oldt = t;
