public Dfp power10(final int e) {
    Dfp d = newInstance(getOne());

    if (e >= 0) {
        d.exp = e / 4 + 1;
    } else {
        d.exp = (e + 1) / 4;
    }

    switch ((e % 4 + 4) % 4) {
        case 0:
            break;
        case 1:
            d = d.multiply(10);
            break;
        case 2:
            d = d.multiply(100);
            break;
        default:
            d = d.multiply(1000);
    }

    return d;
}


public Dfp remainder(final Dfp d) {

    final Dfp result = this.subtract(this.divide(d).rint().multiply(d));


    if (result.mant[mant.length-1] == 0) {
        result.sign = sign;
    }

    return result;

}


protected int round(int n) {
    boolean inc = false;
    switch (field.getRoundingMode()) {
        case ROUND_DOWN:
            inc = false;
            break;

        case ROUND_UP:
            inc = n != 0;       
            break;

        case ROUND_HALF_UP:
            inc = n >= 5000;  
            break;

        case ROUND_HALF_DOWN:
            inc = n > 5000;  
            break;

        case ROUND_HALF_EVEN:
            inc = n > 5000 || (n == 5000 && (mant[0] & 1) == 1);  
            break;

        case ROUND_HALF_ODD:
            inc = n > 5000 || (n == 5000 && (mant[0] & 1) == 0);  
            break;

        case ROUND_CEIL:
            inc = sign == 1 && n != 0;  
            break;

        case ROUND_FLOOR:
        default:
            inc = sign == -1 && n != 0;  
            break;
    }

    if (inc) {

        int rh = 1;
        for (int i = 0; i < mant.length; i++) {
            final int r = mant[i] + rh;
            rh = r / RADIX;
            mant[i] = r - rh * RADIX;
        }

        if (rh != 0) {
            shiftRight();
            mant[mant.length-1] = rh;
        }
    }


    if (exp < MIN_EXP) {

        field.setIEEEFlagsBits(DfpField.FLAG_UNDERFLOW);
        return DfpField.FLAG_UNDERFLOW;
    }

    if (exp > MAX_EXP) {

        field.setIEEEFlagsBits(DfpField.FLAG_OVERFLOW);
        return DfpField.FLAG_OVERFLOW;
    }

    if (n != 0) {

        field.setIEEEFlagsBits(DfpField.FLAG_INEXACT);
        return DfpField.FLAG_INEXACT;
    }

    return 0;

}


