public double inverseCumulativeProbability(double p)
    throws OutOfRangeException {
    if (p < 0 || p > 1) {
        throw new OutOfRangeException(p, 0, 1);
    }
    if (p == 0) {
        return a;
    }
    if (p == 1) {
        return b;
    }
    if (p < (c - a) / (b - a)) {
        return a + FastMath.sqrt(p * (b - a) * (c - a));
    }
    return b - FastMath.sqrt((1 - p) * (b - a) * (b - c));
}

