    for (int blockIndex = 0; blockIndex < out.blocks.length; ++blockIndex) {
        final T[] outBlock = out.blocks[blockIndex];
        final T[] tBlock   = blocks[blockIndex];
        for (int k = 0; k < outBlock.length; ++k) {
            outBlock[k] = tBlock[k].multiply(d);
        }
    }

    return out;
}

