public RealMatrix getH() {
    if (cachedH == null) {

        final int n = qrt.length;
        final int m = qrt[0].length;
        double[][] ha = new double[m][n];
        for (int i = 0; i < m; ++i) {
            for (int j = 0; j < FastMath.min(i + 1, n); ++j) {
                ha[i][j] = qrt[j][i] / -rDiag[j];
            }
        }
        cachedH = MatrixUtils.createRealMatrix(ha);
