    OpenIntToFieldHashMap<T>.Iterator iter = res.entries.iterator();
    while (iter.hasNext()) {
        iter.advance();
        res.setEntry(iter.key(), iter.value().divide(v.getEntry(iter.key())));
    }
    return res;
}


