    throws MaxCountExceededException {

  if (steps.size() == 0) {
    initialTime = interpolator.getPreviousTime();
    forward     = interpolator.isForward();
  }

  steps.add(interpolator.copy());

  if (isLast) {
    finalTime = interpolator.getCurrentTime();
    index     = steps.size() - 1;
  }

}


