    if (!Double.isNaN(cachedNormalDeviate)) {
        double dev = cachedNormalDeviate;
        cachedNormalDeviate = Double.NaN;
        return dev;
    }
    double v1 = 0;
    double v2 = 0;
    double s = 1;
    while (s >=1 ) {
        v1 = 2 * nextDouble() - 1;
        v2 = 2 * nextDouble() - 1;
        s = v1 * v1 + v2 * v2;
    }
    if (s != 0) {
        s = FastMath.sqrt(-2 * FastMath.log(s) / s);
    }
    cachedNormalDeviate = v2 * s;
    return v1 * s;
}


