public double getResult() {
    double kurtosis = Double.NaN;
    if (moment.getN() > 3) {
        double variance = moment.m2 / (moment.n - 1);
            if (moment.n <= 3 || variance < 10E-20) {
                kurtosis = 0.0;
            } else {
                double n = moment.n;
                kurtosis =
                    (n * (n + 1) * moment.getResult() -
                            3 * moment.m2 * moment.m2 * (n - 1)) /
                            ((n - 1) * (n -2) * (n -3) * variance * variance);
            }
    }
    return kurtosis;
}

