public double getSignificance() {
    if (n < 3) {
        return Double.NaN;
    }

    TDistribution distribution = new TDistribution(n - 2);
    return 2d * (1.0 - distribution.cumulativeProbability(
                FastMath.abs(getSlope()) / getSlopeStdErr()));
}


