public static double scalb(final double d, final int n) {


    if ((n > -1023) && (n < 1024)) {
        return d * Double.longBitsToDouble(((long) (n + 1023)) << 52);
    }


    if (Double.isNaN(d) || Double.isInfinite(d) || (d == 0)) {
        return d;
    }
    if (n < -2098) {
        return (d > 0) ? 0.0 : -0.0;
    }
    if (n > 2097) {
        return (d > 0) ? Double.POSITIVE_INFINITY : Double.NEGATIVE_INFINITY;
    }


    final long bits = Double.doubleToLongBits(d);
    final long sign = bits & 0x8000000000000000L;
    int  exponent   = ((int) (bits >>> 52)) & 0x7ff;
    long mantissa   = bits & 0x000fffffffffffffL;


    int scaledExponent = exponent + n;

    if (n < 0) {

        if (scaledExponent > 0) {

            return Double.longBitsToDouble(sign | (((long) scaledExponent) << 52) | mantissa);
        } else if (scaledExponent > -53) {



            mantissa = mantissa | (1L << 52);


            final long mostSignificantLostBit = mantissa & (1L << (-scaledExponent));
            mantissa = mantissa >>> (1 - scaledExponent);
            if (mostSignificantLostBit != 0) {

                mantissa++;
            }
            return Double.longBitsToDouble(sign | mantissa);

        } else {

            return (sign == 0L) ? 0.0 : -0.0;
        }
    } else {

        if (exponent == 0) {


            while ((mantissa >>> 52) != 1) {
                mantissa = mantissa << 1;
                --scaledExponent;
            }
            ++scaledExponent;
            mantissa = mantissa & 0x000fffffffffffffL;

            if (scaledExponent < 2047) {
                return Double.longBitsToDouble(sign | (((long) scaledExponent) << 52) | mantissa);
            } else {
                return (sign == 0L) ? Double.POSITIVE_INFINITY : Double.NEGATIVE_INFINITY;
            }

        } else if (scaledExponent < 2047) {
            return Double.longBitsToDouble(sign | (((long) scaledExponent) << 52) | mantissa);
        } else {
            return (sign == 0L) ? Double.POSITIVE_INFINITY : Double.NEGATIVE_INFINITY;
        }
    }

}


public static double ulp(double x) {
    if (Double.isInfinite(x)) {
        return Double.POSITIVE_INFINITY;
    }
    return abs(x - Double.longBitsToDouble(Double.doubleToLongBits(x) ^ 1));
}

private static void buildSinCosTables(double[] SINE_TABLE_A, double[] SINE_TABLE_B,
                                      double[] COSINE_TABLE_A, double[] COSINE_TABLE_B,
                                      int SINE_TABLE_LEN, double[] TANGENT_TABLE_A, double[] TANGENT_TABLE_B) {
    final double result[] = new double[2];


    for (int i = 0; i < 7; i++) {
        double x = i / 8.0;

        slowSin(x, result);
        SINE_TABLE_A[i] = result[0];
        SINE_TABLE_B[i] = result[1];

        slowCos(x, result);
        COSINE_TABLE_A[i] = result[0];
        COSINE_TABLE_B[i] = result[1];
    }


    for (int i = 7; i < SINE_TABLE_LEN; i++) {
        double xs[] = new double[2];
        double ys[] = new double[2];
        double as[] = new double[2];
        double bs[] = new double[2];
        double temps[] = new double[2];

        if ( (i & 1) == 0) {

            xs[0] = SINE_TABLE_A[i/2];
            xs[1] = SINE_TABLE_B[i/2];
            ys[0] = COSINE_TABLE_A[i/2];
            ys[1] = COSINE_TABLE_B[i/2];


            splitMult(xs, ys, result);
            SINE_TABLE_A[i] = result[0] * 2.0;
            SINE_TABLE_B[i] = result[1] * 2.0;


            splitMult(ys, ys, as);
            splitMult(xs, xs, temps);
            temps[0] = -temps[0];
            temps[1] = -temps[1];
            splitAdd(as, temps, result);
            COSINE_TABLE_A[i] = result[0];
            COSINE_TABLE_B[i] = result[1];
        } else {
            xs[0] = SINE_TABLE_A[i/2];
            xs[1] = SINE_TABLE_B[i/2];
            ys[0] = COSINE_TABLE_A[i/2];
            ys[1] = COSINE_TABLE_B[i/2];
            as[0] = SINE_TABLE_A[i/2+1];
            as[1] = SINE_TABLE_B[i/2+1];
            bs[0] = COSINE_TABLE_A[i/2+1];
            bs[1] = COSINE_TABLE_B[i/2+1];


            splitMult(xs, bs, temps);
            splitMult(ys, as, result);
            splitAdd(result, temps, result);
            SINE_TABLE_A[i] = result[0];
            SINE_TABLE_B[i] = result[1];


            splitMult(ys, bs, result);
            splitMult(xs, as, temps);
            temps[0] = -temps[0];
            temps[1] = -temps[1];
            splitAdd(result, temps, result);
            COSINE_TABLE_A[i] = result[0];
            COSINE_TABLE_B[i] = result[1];
        }
    }


    for (int i = 0; i < SINE_TABLE_LEN; i++) {
        double xs[] = new double[2];
        double ys[] = new double[2];
        double as[] = new double[2];

        as[0] = COSINE_TABLE_A[i];
        as[1] = COSINE_TABLE_B[i];

        splitReciprocal(as, ys);

        xs[0] = SINE_TABLE_A[i];
        xs[1] = SINE_TABLE_B[i];

        splitMult(xs, ys, as);

        TANGENT_TABLE_A[i] = as[0];
        TANGENT_TABLE_B[i] = as[1];
    }

}


static double expint(int p, final double result[]) {

    final double xs[] = new double[2];
    final double as[] = new double[2];
    final double ys[] = new double[2];








    xs[0] = 2.718281828459045;
    xs[1] = 1.4456468917292502E-16;

    split(1.0, ys);

    while (p > 0) {
        if ((p & 1) != 0) {
            quadMult(ys, xs, as);
            ys[0] = as[0]; ys[1] = as[1];
        }

        quadMult(xs, xs, as);
        xs[0] = as[0]; xs[1] = as[1];

        p >>= 1;
    }

    if (result != null) {
        result[0] = ys[0];
        result[1] = ys[1];

        resplit(result);
    }

    return ys[0] + ys[1];
}


static double[] slowLog(double xi) {
    double x[] = new double[2];
    double x2[] = new double[2];
    double y[] = new double[2];
    double a[] = new double[2];

    split(xi, x);


    x[0] += 1.0;
    resplit(x);
    splitReciprocal(x, a);
    x[0] -= 2.0;
    resplit(x);
    splitMult(x, a, y);
    x[0] = y[0];
    x[1] = y[1];


    splitMult(x, x, x2);





    y[0] = LN_SPLIT_COEF[LN_SPLIT_COEF.length-1][0];
    y[1] = LN_SPLIT_COEF[LN_SPLIT_COEF.length-1][1];

    for (int i = LN_SPLIT_COEF.length-2; i >= 0; i--) {
        splitMult(y, x2, a);
        y[0] = a[0];
        y[1] = a[1];
        splitAdd(y, LN_SPLIT_COEF[i], a);
        y[0] = a[0];
        y[1] = a[1];
    }

    splitMult(y, x, a);
    y[0] = a[0];
    y[1] = a[1];

    return y;
}


static double slowexp(final double x, final double result[]) {
    final double xs[] = new double[2];
    final double ys[] = new double[2];
    final double facts[] = new double[2];
    final double as[] = new double[2];
    split(x, xs);
    ys[0] = ys[1] = 0.0;

    for (int i = FACT.length-1; i >= 0; i--) {
        splitMult(xs, ys, as);
        ys[0] = as[0];
        ys[1] = as[1];

        split(FACT[i], as);
        splitReciprocal(as, facts);

        splitAdd(ys, facts, as);
        ys[0] = as[0];
        ys[1] = as[1];
    }

    if (result != null) {
        result[0] = ys[0];
        result[1] = ys[1];
    }

    return ys[0] + ys[1];
}


