public static  <T extends Comparable<? super T>> boolean isMonotonic(T[] val,
                                  OrderDirection dir,
                                  boolean strict) {
    T previous = val[0];
    final int max = val.length;
    for (int i = 1; i < max; i++) {
        final int comp;
        switch (dir) {
        case INCREASING:
            comp = previous.compareTo(val[i]);
            if (strict) {
                if (comp >= 0) {
                    return false;
                }
            } else {
                if (comp > 0) {
                    return false;
                }
            }
            break;
        case DECREASING:
            comp = val[i].compareTo(previous);
            if (strict) {
                if (comp >= 0) {
                    return false;
                }
            } else {
                if (comp > 0) {
                   return false;
                }
            }
            break;
        default:

            throw new MathInternalError();
        }

        previous = val[i];
    }
    return true;
}


